{"code":"import os
terms=['to_dest_dev_base','to_dest','dest_dev','token','TOKEN']
for root in [r'C:\Users\12159\Desktop\Singularity', r'C:\Users\12159\Desktop\transition']:
 print('---',root)
 for dp, dns, fs in os.walk(root):
  dns[:] = [d for d in dns if d not in {'.git','cache','tmp_visual_test'}]
  for f in fs:
   if os.path.splitext(f)[1].lower() not in {'.c','.h','.cpp','.hpp','.go','.txt'}: continue
   path=os.path.join(dp,f)
   try:
    s=open(path,'r',encoding='utf-8',errors='ignore').read()
   except: continue
   hits=[t for t in terms if t in s]
   if hits:
    print(path, hits)"}

